#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
   int val;
   struct Node* left;
   struct Node* right;
} Node;

void findMinAndMax(Node* root, int* min, int* max) {
   if (root == NULL) return;

   if (*min == 0 || root->val < *min) *min = root->val;
   if (*max == 0 || root->val > *max) *max = root->val;

   findMinAndMax(root->left, min, max);
   findMinAndMax(root->right, min, max);
}

int main() {
   Node* root = (Node*)malloc(sizeof(Node));
   root->val = 8;
   root->left = (Node*)malloc(sizeof(Node));
   root->right = (Node*)malloc(sizeof(Node));

   root->left->val = 3;
   root->right->val = 10;

   root->left->left = (Node*)malloc(sizeof(Node));
   root->left->right = (Node*)malloc(sizeof(Node));

   root->left->left->val = 1;
   root->left->right->val = 6;

   root->right->right = (Node*)malloc(sizeof(Node));
   root->right->right->val = 14;

   int min = 0;
   int max = 0;

   findMinAndMax(root, &min, &max);

   printf("Min: %d, Max: %d\n", min, max);

   return 0;
}

