public class Main {
   static class Node {
      int val;
      Node left;
      Node right;

      Node(int val) {
         this.val = val;
      }
   }

   public static void findMinAndMax(Node root, int[] minMax) {
      if (root == null) return;

      if (minMax[0] == 0 || root.val < minMax[0]) minMax[0] = root.val;
      if (minMax[1] == 0 || root.val > minMax[1]) minMax[1] = root.val;

      findMinAndMax(root.left, minMax);
      findMinAndMax(root.right, minMax);
   }

   public static void main(String[] args) {
      Node root = new Node(8);
      root.left = new Node(3);
      root.right = new Node(10);

      root.left.left = new Node(1);
      root.left.right = new Node(6);

      root.right.right = new Node(14);

      int[] minMax = new int[] {0, 0};

      findMinAndMax(root, minMax);

      System.out.println("Min: " + minMax[0] + ", Max: " + minMax[1]);
   }
}

