class Node {
   constructor(val) {
      this.val = val;
      this.left = null;
      this.right = null;
   }
}

function findMinAndMax(root) {
   if (root === null) return [null, null];

   let min = root.val;
   let max = root.val;

   let left = findMinAndMax(root.left);
   let right = findMinAndMax(root.right);

   if (left[0] !== null && left[0] < min) min = left[0];
   if (right[0] !== null && right[0] < min) min = right[0];

   if (left[1] !== null && left[1] > max) max = left[1];
   if (right[1] !== null && right[1] > max) max = right[1];

   return [min, max];
}

let root = new Node(8);
root.left = new Node(3);
root.right = new Node(10);

root.left.left = new Node(1);
root.left.right = new Node(6);

root.right.right = new Node(14);

let [min, max] = findMinAndMax(root);

console.log(`Min: ${min}, Max: ${max}`);
